    public Object parseBalance(Object response)
    {
        Object balances = this.safeDict(response, "return", new java.util.HashMap<String, Object>() {{}});
        Object timestamp = this.safeInteger(balances, "server_time");
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
            put( "timestamp", timestamp );
            put( "datetime", YobitCore.this.iso8601(timestamp) );
        }};
        Object free = this.safeDict(balances, "funds", new java.util.HashMap<String, Object>() {{}});
        Object total = this.safeDict(balances, "funds_incl_orders", new java.util.HashMap<String, Object>() {{}});
        Object currencyIds = Helpers.objectKeys(this.extend(free, total));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(currencyIds)); i++)
        {
            Object currencyId = Helpers.GetValue(currencyIds, i);
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "free", this.safeString(free, currencyId));
            Helpers.addElementToObject(account, "total", this.safeString(total, currencyId));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

