    /**
     * @method
     * @name yobit#fetchOrderBook
     * @see https://yobit.net/en/api
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure} indexed by market symbols
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit); // default = 150, max = 2000
            }
            Object response = (this.publicGetDepthPair(this.extend(request, parameters))).join();
            Object market_id_in_reponse = (Helpers.inOp(response, Helpers.GetValue(market, "id")));
            if (!Helpers.isTrue(market_id_in_reponse))
            {
                throw new ExchangeError((String)Helpers.add(Helpers.add(Helpers.add(this.id, " "), Helpers.GetValue(market, "symbol")), " order book is empty or not available")) ;
            }
            Object orderbook = Helpers.GetValue(response, Helpers.GetValue(market, "id"));
            return this.parseOrderBook(orderbook, symbol);
        });

    }

    /**
     * @method
     * @name yobit#fetchOrderBooks
     * @see https://yobit.net/en/api
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data for multiple markets
     * @param {string[]|undefined} symbols list of unified market symbols, all symbols fetched if undefined, default is undefined
     * @param {int} [limit] max number of entries per orderbook to return, default is undefined
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure} indexed by market symbol
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBooks(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object ids = null;
            if (Helpers.isTrue(Helpers.isEqual(symbols, null)))
            {
                Object allIds = this.ids;
                ids = String.join((String)"-", (java.util.List<String>)allIds);
                // max URL length is 2083 symbols, including http schema, hostname, tld, etc...
                if (Helpers.isTrue(Helpers.isGreaterThan(Helpers.getArrayLength(ids), 2048)))
                {
                    Object numIds = Helpers.getArrayLength(this.ids);
                    throw new ExchangeError((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchOrderBooks() has "), String.valueOf(numIds)), " symbols exceeding max URL length, you are required to specify a list of symbols in the first argument to fetchOrderBooks")) ;
                }
            } else
            {
                ids = this.marketIds(symbols);
                ids = String.join((String)"-", (java.util.List<String>)ids);
            }
            final Object finalIds = ids;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", finalIds );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object response = (this.publicGetDepthPair(this.extend(request, parameters))).join();
            Object result = new java.util.HashMap<String, Object>() {{}};
            ids = Helpers.objectKeys(response);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(ids)); i++)
            {
                Object id = Helpers.GetValue(ids, i);
                Object symbol = this.safeSymbol(id);
                Helpers.addElementToObject(result, symbol, this.parseOrderBook(Helpers.GetValue(response, id), symbol));
            }
            return result;
        });

    }

