    /**
     * @method
     * @name yobit#fetchTickers
     * @see https://yobit.net/en/api
     * @description fetches price tickers for multiple markets, statistical information calculated over the past 24 hours for each market
     * @param {string[]|undefined} symbols unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {object} [params.all] you can set to `true` for convenience to fetch all tickers from this exchange by sending multiple requests
     * @returns {object} a dictionary of [ticker structures]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTickers(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object allSymbols = null;
            var allSymbolsparametersVariable = this.handleParamBool(parameters, "all", false);
            allSymbols = ((java.util.List<Object>) allSymbolsparametersVariable).get(0);
            parameters = ((java.util.List<Object>) allSymbolsparametersVariable).get(1);
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(symbols, null)) && !Helpers.isTrue(allSymbols)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchTickers() requires \"symbols\" argument or use `params[\"all\"] = true` to send multiple requests for all markets")) ;
            }
            (this.loadMarkets()).join();
            Object promises = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object maxLength = this.safeInteger(this.options, "maxUrlLength", 2048);
            // max URL length is 2048 symbols, including http schema, hostname, tld, etc...
            Object lenghtOfBaseUrl = 40; // safe space for the url including api-base and endpoint dir is 30 chars
            if (Helpers.isTrue(allSymbols))
            {
                symbols = this.symbols;
                Object ids = "";
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(this.ids)); i++)
                {
                    Object id = Helpers.GetValue(this.ids, i);
                    Object prefix = ((Helpers.isTrue((Helpers.isEqual(ids, ""))))) ? "" : "-";
                    ids = Helpers.add(ids, Helpers.add(prefix, id));
                    if (Helpers.isTrue(Helpers.isGreaterThan(((String)ids).length(), maxLength)))
                    {
                        ((java.util.List<Object>)promises).add(this.fetchTickersHelper(ids, parameters));
                        ids = "";
                    }
                }
                if (Helpers.isTrue(!Helpers.isEqual(ids, "")))
                {
                    ((java.util.List<Object>)promises).add(this.fetchTickersHelper(ids, parameters));
                }
            } else
            {
                symbols = this.marketSymbols(symbols);
                Object ids = this.marketIds(symbols);
                Object idsLength = Helpers.getArrayLength(ids);
                Object idsString = String.join((String)"-", (java.util.List<String>)ids);
                Object actualLength = Helpers.add(((String)idsString).length(), lenghtOfBaseUrl);
                if (Helpers.isTrue(Helpers.isGreaterThan(actualLength, maxLength)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " fetchTickers() is being requested for "), String.valueOf(idsLength)), " markets (which has an URL length of "), String.valueOf(actualLength)), " characters), but it exceedes max URL length ("), String.valueOf(maxLength)), "), please pass limisted symbols array to fetchTickers to fit in one request")) ;
                }
                ((java.util.List<Object>)promises).add(this.fetchTickersHelper(idsString, parameters));
            }
            Object resultAll = (Helpers.promiseAll(promises)).join();
            Object finalResult = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(resultAll)); i++)
            {
                Object result = this.filterByArrayTickers(Helpers.GetValue(resultAll, i), "symbol", symbols);
                finalResult = this.extend(finalResult, result);
            }
            return finalResult;
        });

    }

    /**
     * @method
     * @name yobit#fetchTicker
     * @see https://yobit.net/en/api
     * @description fetches a price ticker, a statistical calculation with the information calculated over the past 24 hours for a specific market
     * @param {string} symbol unified symbol of the market to fetch the ticker for
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [ticker structure]{@link https://docs.ccxt.com/?id=ticker-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTicker(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object tickers = (this.fetchTickers(new java.util.ArrayList<Object>(java.util.Arrays.asList(symbol)), parameters)).join();
            return Helpers.GetValue(tickers, symbol);
        });

    }

    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //      {
        //          "type":"bid",
        //          "price":0.14046179,
        //          "amount":0.001,
        //          "tid":200256901,
        //          "timestamp":1649861004
        //      }
        //
        // fetchMyTrades (private)
        //
        //      {
        //          "pair":"doge_usdt",
        //          "type":"sell",
        //          "amount":139,
        //          "rate":0.139,
        //          "order_id":"2101103631773172",
        //          "is_your_order":1,
        //          "timestamp":"1649861561"
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeTimestamp(trade, "timestamp");
        Object side = this.safeString(trade, "type");
        if (Helpers.isTrue(Helpers.isEqual(side, "ask")))
        {
            side = "sell";
        } else if (Helpers.isTrue(Helpers.isEqual(side, "bid")))
        {
            side = "buy";
        }
        Object priceString = this.safeString2(trade, "rate", "price");
        Object id = this.safeString2(trade, "trade_id", "tid");
        Object order = this.safeString(trade, "order_id");
        Object marketId = this.safeString(trade, "pair");
        Object symbol = this.safeSymbol(marketId, market);
        Object amountString = this.safeString(trade, "amount");
        // arguments for calculateFee (need to be numbers)
        Object price = this.parseNumber(priceString);
        Object amount = this.parseNumber(amountString);
        Object type = "limit"; // all trades are still limit trades
        Object fee = null;
        Object feeCostString = this.safeNumber(trade, "commission");
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "commissionCurrency");
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", feeCurrencyCode );
            }};
        }
        Object isYourOrder = this.safeString(trade, "is_your_order");
        if (Helpers.isTrue(!Helpers.isEqual(isYourOrder, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(fee, null)))
            {
                Object feeInNumbers = this.calculateFee(symbol, type, side, amount, price, "taker");
                fee = new java.util.HashMap<String, Object>() {{
                    put( "currency", YobitCore.this.safeString(feeInNumbers, "currency") );
                    put( "cost", YobitCore.this.safeString(feeInNumbers, "cost") );
                    put( "rate", YobitCore.this.safeString(feeInNumbers, "rate") );
                }};
            }
        }
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "order", order );
            put( "timestamp", timestamp );
            put( "datetime", YobitCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "type", type );
            put( "side", finalSide );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", finalFee );
            put( "info", trade );
        }}, market);
    }

