            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit);
            }
            Object response = (this.publicGetTradesPair(this.extend(request, parameters))).join();
            //
            //      {
            //          "doge_usdt": [
            //              {
            //                  "type":"ask",
