    /**
     * @method
     * @name yobit#fetchMyTrades
     * @see https://yobit.net/en/api
     * @description fetch all trades made by the user
     * @param {string} symbol unified market symbol
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trades structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchMyTrades() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            // some derived classes use camelcase notation for request fields
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "count", limit);
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "since", this.parseToInt(Helpers.divide(since, 1000)));
            }
            Object response = (this.privatePostTradeHistory(this.extend(request, parameters))).join();
            //
            //      {
            //          "success":1,
            //          "return": {
            //              "200257004": {
            //                  "pair":"doge_usdt",
            //                  "type":"sell",
            //                  "amount":139,
            //                  "rate":0.139,
            //                  "order_id":"2101103631773172",
            //                  "is_your_order":1,
            //                  "timestamp":"1649861561"
            //              }
            //          }
            //      }
            //
            Object trades = this.safeDict(response, "return", new java.util.HashMap<String, Object>() {{}});
            Object ids = Helpers.objectKeys(trades);
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(ids)); i++)
            {
                Object id = this.safeString(ids, i);
                Object trade = this.parseTrade(this.extend(Helpers.GetValue(trades, id), new java.util.HashMap<String, Object>() {{
                    put( "trade_id", id );
                }}), market);
                ((java.util.List<Object>)result).add(trade);
            }
            return this.filterBySymbolSinceLimit(result, Helpers.GetValue(market, "symbol"), since, limit);
        });

    }

    /**
     * @method
     * @name yobit#createDepositAddress
     * @see https://yobit.net/en/api
     * @description create a currency deposit address
     * @param {string} code unified currency code of the currency for the deposit address
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object request = new java.util.HashMap<String, Object>() {{
                put( "need_new", 1 );
            }};
            Object response = (this.fetchDepositAddress(code, this.extend(request, parameters))).join();
            Object address = this.safeString(response, "address");
            this.checkAddress(address);
            return new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "address", address );
                put( "tag", null );
                put( "network", null );
                put( "info", Helpers.GetValue(response, "info") );
            }};
        });

    }

    /**
     * @method
     * @name yobit#fetchDepositAddress
     * @description fetch the deposit address for a currency associated with this account
     * @see https://yobit.net/en/api
     * @param {string} code unified currency code
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object currencyId = Helpers.GetValue(currency, "id");
            Object networks = this.safeDict(this.options, "networks", new java.util.HashMap<String, Object>() {{}});
            Object network = this.safeStringUpper(parameters, "network"); // this line allows the user to specify either ERC20 or ETH
            network = this.safeString(networks, network, network); // handle ERC20>ETH alias
            if (Helpers.isTrue(!Helpers.isEqual(network, null)))
            {
                if (Helpers.isTrue(!Helpers.isEqual(network, "ERC20")))
                {
                    currencyId = Helpers.add(currencyId, ((String)network).toLowerCase());
                }
                parameters = this.omit(parameters, "network");
            }
            final Object finalCurrencyId = currencyId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "coinName", finalCurrencyId );
                put( "need_new", 0 );
            }};
            Object response = (this.privatePostGetDepositAddress(this.extend(request, parameters))).join();
            Object address = this.safeString(Helpers.GetValue(response, "return"), "address");
            this.checkAddress(address);
            return new java.util.HashMap<String, Object>() {{
                put( "info", response );
                put( "currency", code );
                put( "network", null );
                put( "address", address );
                put( "tag", null );
            }};
        });

    }

